@startuml

abstract class Duck {
    {abstract} public abstract void display()
    void quack()
    void swim()
    void fly()
}

class WildDuck {
    void display()
}

class PekingDuck {
    void display()
    void fly()
}

class ToyDuck {
    void display()
    void quack()
    void swim()
    void fly()
}

WildDuck --|> Duck
PekingDuck --|> Duck
ToyDuck --|> Duck

@enduml
